INSERT INTO novels (id, author_id, title, slug, description, cover_image_url, status, view_count, created_at, updated_at) VALUES
                                                                                                                              ('99a75b58-54c1-547d-b4a1-c61de7cce305', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Shadow Academy', 'shadow-academy', 'A gifted student enters an academy where every exam reveals an old secret and every friendship carries a hidden cost.', 'https://picsum.photos/seed/shadow-academy/400/600', 'ongoing', 387, DATEADD('DAY', -7, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('d68475cb-33ee-5ebe-8995-917ebcb219f4', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Starlight Courier', 'starlight-courier', 'A young courier crosses dangerous star lanes to deliver a message that can stop an interplanetary war.', 'https://picsum.photos/seed/starlight-courier/400/600', 'ongoing', 524, DATEADD('DAY', -14, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('3a1db293-75ba-5721-b24d-0cfea350e613', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Crimson Blade', 'crimson-blade', 'An exiled swordsman searches for the truth behind a fallen kingdom while hunters close in from every border.', 'https://picsum.photos/seed/crimson-blade/400/600', 'completed', 661, DATEADD('DAY', -21, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('9bba499d-d5bd-5dbb-a843-c79b2518faf3', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Moonlit Contract', 'moonlit-contract', 'A reluctant heir signs a magical contract with a rival family and discovers loyalty is harder than betrayal.', 'https://picsum.photos/seed/moonlit-contract/400/600', 'ongoing', 798, DATEADD('DAY', -28, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('d5f906cc-3bab-5eb7-a06e-dc9d96461765', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Clockwork City', 'clockwork-city', 'In a city powered by living machines, an apprentice mechanic finds a map to the engine beneath the world.', 'https://picsum.photos/seed/clockwork-city/400/600', 'ongoing', 935, DATEADD('DAY', -35, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('b5b699fe-2df4-5479-9b81-f6b516c1a264', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'River of Ashes', 'river-of-ashes', 'A healer follows a poisoned river upstream and uncovers the army that turned villages into silence.', 'https://picsum.photos/seed/river-of-ashes/400/600', 'completed', 1072, DATEADD('DAY', -42, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('1a4f3d78-1820-513a-b491-212ce8042649', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Lanterns After Rain', 'lanterns-after-rain', 'Two neighbors rebuild a flooded town and slowly learn that old letters can change the shape of tomorrow.', 'https://picsum.photos/seed/lanterns-after-rain/400/600', 'ongoing', 1209, DATEADD('DAY', -49, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('ca7b407f-1527-5268-8d9e-343aad696689', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'The Ninth Gate', 'the-ninth-gate', 'A historian opens the wrong gate in an ancient temple and wakes a guardian who remembers the first war.', 'https://picsum.photos/seed/the-ninth-gate/400/600', 'ongoing', 1346, DATEADD('DAY', -56, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('b5269c95-8b72-5d07-a252-c16584df1726', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Neon Detective', 'neon-detective', 'A private detective in a rain-soaked megacity investigates a missing android with memories that should not exist.', 'https://picsum.photos/seed/neon-detective/400/600', 'ongoing', 1483, DATEADD('DAY', -63, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('80535776-4d05-5f94-96a7-37269b4cd3c9', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Empire of Glass', 'empire-of-glass', 'A palace translator hears a prophecy in a forbidden language and becomes the target of nobles on every side.', 'https://picsum.photos/seed/empire-of-glass/400/600', 'completed', 1620, DATEADD('DAY', -70, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('c9854de9-b9ba-5794-ba79-419ff35da124', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Hollow Crown', 'hollow-crown', 'A prince who faked his own death returns as a nameless soldier and must reclaim a throne held by someone who wears his face.', 'https://picsum.photos/seed/hollow-crown/400/600', 'ongoing', 1757, DATEADD('DAY', -77, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('56feca8f-55ce-5154-bf96-cc6271c7ae7f', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Signal Bloom', 'signal-bloom', 'An agronomist on a dying colony planet discovers that the soil is transmitting an encoded signal from deep underground.', 'https://picsum.photos/seed/signal-bloom/400/600', 'ongoing', 1894, DATEADD('DAY', -84, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('3a4e584f-c812-5b2c-b03a-409049d68ff7', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Veil of Salt', 'veil-of-salt', 'A bride-to-be discovers that the coastal town she is marrying into holds a ritual that erases one memory from every newcomer.', 'https://picsum.photos/seed/veil-of-salt/400/600', 'ongoing', 2031, DATEADD('DAY', -91, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('013f1662-d1f0-54cd-9e1c-368101e75759', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Iron Nomad', 'iron-nomad', 'A wandering mechanic crosses a post-war wasteland repairing machines and slowly pieces together who started the war.', 'https://picsum.photos/seed/iron-nomad/400/600', 'completed', 2168, DATEADD('DAY', -98, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('98aefb9e-1861-59ba-973e-fc54d777fb65', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Glass Garden', 'glass-garden', 'A gardener inside an enchanted greenhouse tends plants that bloom once per century and discovers one is about to flower for the last time.', 'https://picsum.photos/seed/glass-garden/400/600', 'ongoing', 2305, DATEADD('DAY', -105, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('c915e4bd-a513-59da-85df-24258cb1895d', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Parallel Desk', 'parallel-desk', 'An office worker receives messages from herself in a parallel timeline where she made every different choice.', 'https://picsum.photos/seed/parallel-desk/400/600', 'ongoing', 2442, DATEADD('DAY', -112, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('69333d26-8511-56e1-8a07-e58a44cb67ce', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Dust Oracle', 'dust-oracle', 'A desert trader stumbles upon an oracle buried under three centuries of sand who speaks only in riddles about the next catastrophe.', 'https://picsum.photos/seed/dust-oracle/400/600', 'completed', 2579, DATEADD('DAY', -119, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('95f34a48-9034-5c66-8615-ec00064f3fc2', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'The Cartographer''s Lie', 'the-cartographers-lie', 'A royal cartographer learns that every map she has ever drawn contains a hidden error that leads travelers toward a forbidden zone.', 'https://picsum.photos/seed/the-cartographers-lie/400/600', 'ongoing', 2716, DATEADD('DAY', -126, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('519dc999-cf18-57de-8858-45cf18b794e2', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Second Skin', 'second-skin', 'An undercover agent falls in love with the target of her investigation and must decide which identity is the real one.', 'https://picsum.photos/seed/second-skin/400/600', 'ongoing', 2853, DATEADD('DAY', -133, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP),
                                                                                                                              ('8d2c6065-4d66-5d7f-8349-b8381f337f23', '70eb648d-5444-5a43-bde1-06f8dab7d62a', 'Fog Parliament', 'fog-parliament', 'A junior delegate arrives at a fog-shrouded parliament where votes disappear overnight and the majority is always whoever woke up last.', 'https://picsum.photos/seed/fog-parliament/400/600', 'ongoing', 2990, DATEADD('DAY', -140, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
