INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('0032263a-63cc-53d4-a5f8-72826496f559', '99a75b58-54c1-547d-b4a1-c61de7cce305', 1, 'Chapter 1: First Signal', 'shadow-academy-chapter-1', 'Novel: Shadow Academy. Chapter 1 - First Signal. Premise: A gifted student enters an academy where every exam reveals an old secret and every friendship carries a hidden cost. This chapter belongs to the magic school and secret trials arc and keeps the tone of fantasy mystery with tense school rivalries and secret magic. The scene follows Elian Voss through a moonlit academy built above sealed catacombs and watched by living portraits. Central conflict: each exam exposes a forbidden ritual connected to Elian''s missing family, while classmates may be allies or spies. The opening scene introduces the ordinary rhythm of the world, then breaks it with a signal that only the protagonist understands. The chapter focuses on atmosphere, the first hint of danger, and the personal reason the protagonist cannot walk away. In this chapter, Elian Voss notices a detail that matches the novel title and its promise: shadows inside the academy behave like witnesses, turning a school test into a magical investigation. By the final paragraph, the chapter gives readers a concrete development, a character choice, and a hook for the next chapter.', TRUE, 0, 64, DATEADD('DAY', -29, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('a2db5a9f-83cc-580b-b179-a0024c207eb9', '99a75b58-54c1-547d-b4a1-c61de7cce305', 2, 'Chapter 2: Unwanted Invitation', 'shadow-academy-chapter-2', 'Novel: Shadow Academy. Chapter 2 - Unwanted Invitation. Premise: A gifted student enters an academy where every exam reveals an old secret and every friendship carries a hidden cost. This chapter belongs to the magic school and secret trials arc and keeps the tone of fantasy mystery with tense school rivalries and secret magic. The scene follows Elian Voss through a moonlit academy built above sealed catacombs and watched by living portraits. Central conflict: each exam exposes a forbidden ritual connected to Elian''s missing family, while classmates may be allies or spies. A powerful figure offers help with conditions attached. The protagonist accepts because the mystery has already touched home, but the decision creates tension with someone who believes the offer is a trap. In this chapter, Elian Voss notices a detail that matches the novel title and its promise: shadows inside the academy behave like witnesses, turning a school test into a magical investigation. By the final paragraph, the chapter gives readers a concrete development, a character choice, and a hook for the next chapter.', TRUE, 0, 73, DATEADD('DAY', -28, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('aa395bb4-1ea8-5072-ad1e-f9dc8250ab4a', '99a75b58-54c1-547d-b4a1-c61de7cce305', 3, 'Chapter 3: Rules of the Road', 'shadow-academy-chapter-3', 'Novel: Shadow Academy. Chapter 3 - Rules of the Road. Premise: A gifted student enters an academy where every exam reveals an old secret and every friendship carries a hidden cost. This chapter belongs to the magic school and secret trials arc and keeps the tone of fantasy mystery with tense school rivalries and secret magic. The scene follows Elian Voss through a moonlit academy built above sealed catacombs and watched by living portraits. Central conflict: each exam exposes a forbidden ritual connected to Elian''s missing family, while classmates may be allies or spies. The protagonist learns the rules that govern this world: who has power, what is forbidden, and what price people pay for disobedience. A small test proves that the threat is real. In this chapter, Elian Voss notices a detail that matches the novel title and its promise: shadows inside the academy behave like witnesses, turning a school test into a magical investigation. By the final paragraph, the chapter gives readers a concrete development, a character choice, and a hook for the next chapter.', TRUE, 0, 82, DATEADD('DAY', -27, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
