INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('2af6d7c3-f48c-52c1-aab7-8711f849031e', '8d2c6065-4d66-5d7f-8349-b8381f337f23', 1, 'Chapter 1: First Signal', 'fog-parliament-chapter-1', 'Novel: Fog Parliament. Chapter 1 - First Signal. Premise: A junior delegate arrives at a fog-shrouded parliament where votes disappear overnight and the majority is always whoever woke up last. This chapter belongs to the political manipulation and supernatural fog arc and keeps the tone of fantasy mystery with sharp political satire, supernatural logic, and dry wit. The scene follows Delegate Oswin Frey through a parliament building perpetually wrapped in coastal fog, with ink-stained corridors and offices that rearrange nightly. Central conflict: Oswin must pass a land-rights bill before the fog erases the vote record again, and someone is feeding the fog deliberately. The opening scene introduces the ordinary rhythm of the world, then breaks it with a signal that only the protagonist understands. The chapter focuses on atmosphere, the first hint of danger, and the personal reason the protagonist cannot walk away. In this chapter, Delegate Oswin Frey notices a detail that matches the novel title and its promise: the fog parliament''s mist thins for exactly one minute at dawn, long enough to read the vote that was supposed to disappear. By the final paragraph, the chapter gives readers a concrete development, a character choice, and a hook for the next chapter.', TRUE, 0, 349, DATEADD('DAY', -599, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
