INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('58580b59-871b-5325-b701-99239f4e4d4a', '3a1db293-75ba-5721-b24d-0cfea350e613', 21, 'Chapter 21: Extended Arc 1', 'crimson-blade-chapter-21', 'Novel: Crimson Blade. Chapter 21 - Extended Arc 1. This paid extra chapter continues after the first twenty chapters and keeps the same sword fights and royal revenge direction. Premise reminder: An exiled swordsman searches for the truth behind a fallen kingdom while hunters close in from every border. The scene follows Kael Ardent through border forts, ruined royal roads, and mountain passes stained by old battles, with the main conflict still pressing forward: Kael must prove who betrayed the crown before assassins erase every witness from the fallen kingdom. Kael follows the surviving royal standard through border tunnels, and each duel reveals another name from the list of traitors. The chapter advances the extended arc by focusing on step 1 of 3: a new clue appears, but accepting it forces the protagonist to trust someone whose motives remain unclear. By the ending, chapter 21 has its own event, its own decision, and a hook that continues naturally from chapter 20.', FALSE, 40, 274, DATEADD('DAY', 1, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('9083afc9-2115-535d-829b-fd4af74b6c39', '3a1db293-75ba-5721-b24d-0cfea350e613', 22, 'Chapter 22: Extended Arc 2', 'crimson-blade-chapter-22', 'Novel: Crimson Blade. Chapter 22 - Extended Arc 2. This paid extra chapter continues after the first twenty chapters and keeps the same sword fights and royal revenge direction. Premise reminder: An exiled swordsman searches for the truth behind a fallen kingdom while hunters close in from every border. The scene follows Kael Ardent through border forts, ruined royal roads, and mountain passes stained by old battles, with the main conflict still pressing forward: Kael must prove who betrayed the crown before assassins erase every witness from the fallen kingdom. Kael follows the surviving royal standard through border tunnels, and each duel reveals another name from the list of traitors. The chapter advances the extended arc by focusing on step 2 of 3: the clue leads into a confrontation where the protagonist wins information but loses a safe route. By the ending, chapter 22 has its own event, its own decision, and a hook that continues naturally from chapter 21.', FALSE, 45, 283, DATEADD('DAY', 2, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
