INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('cbce96ae-a1dc-5858-a365-1b342bb622b4', 'd5f906cc-3bab-5eb7-a06e-dc9d96461765', 21, 'Chapter 21: Extended Arc 1', 'clockwork-city-chapter-21', 'Novel: Clockwork City. Chapter 21 - Extended Arc 1. This paid extra chapter continues after the first twenty chapters and keeps the same mechanical wonders and urban mystery direction. Premise reminder: In a city powered by living machines, an apprentice mechanic finds a map to the engine beneath the world. The scene follows Ivo Renn through a brass-and-glass city where streets shift when the central engine dreams, with the main conflict still pressing forward: Ivo discovers that the living machines are failing because someone is stealing time from the city core. Ivo descends closer to the buried engine, where every repaired gear changes a street above and exposes the saboteur''s route. The chapter advances the extended arc by focusing on step 1 of 4: a new clue appears, but accepting it forces the protagonist to trust someone whose motives remain unclear. By the ending, chapter 21 has its own event, its own decision, and a hook that continues naturally from chapter 20.', FALSE, 40, 304, DATEADD('DAY', 1, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
