INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('8f5f882e-23dd-55aa-b970-47c6c20c3646', 'ca7b407f-1527-5268-8d9e-343aad696689', 21, 'Chapter 21: Extended Arc 1', 'the-ninth-gate-chapter-21', 'Novel: The Ninth Gate. Chapter 21 - Extended Arc 1. This paid extra chapter continues after the first twenty chapters and keeps the same ancient ruins and mythic guardians direction. Premise reminder: A historian opens the wrong gate in an ancient temple and wakes a guardian who remembers the first war. The scene follows Dr. Ansel Rook through desert temples, buried libraries, and nine stone gates aligned with forgotten stars, with the main conflict still pressing forward: Ansel awakens a guardian whose memory of the first war may either save the world or restart it. Ansel and the awakened guardian cross the temples beyond the ninth gate, translating star inscriptions before rival explorers can weaponize them. The chapter advances the extended arc by focusing on step 1 of 15: a new clue appears, but accepting it forces the protagonist to trust someone whose motives remain unclear. By the ending, chapter 21 has its own event, its own decision, and a hook that continues naturally from chapter 20.', FALSE, 40, 349, DATEADD('DAY', 1, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
