INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('38cb562f-ce05-5d56-9068-1d7fde6f61d9', 'b5269c95-8b72-5d07-a252-c16584df1726', 21, 'Chapter 21: Extended Arc 1', 'neon-detective-chapter-21', 'Novel: Neon Detective. Chapter 21 - Extended Arc 1. This paid extra chapter continues after the first twenty chapters and keeps the same cyberpunk investigation and identity direction. Premise reminder: A private detective in a rain-soaked megacity investigates a missing android with memories that should not exist. The scene follows Juno Park through neon alleys, data markets, and corporate towers above a rain-soaked megacity, with the main conflict still pressing forward: Juno must find a missing android whose illegal memories implicate the corporation that owns the police. Juno tracks the missing android through data markets, memory clinics, and corporate dead zones where every witness has been edited. The chapter advances the extended arc by focusing on step 1 of 17: a new clue appears, but accepting it forces the protagonist to trust someone whose motives remain unclear. By the ending, chapter 21 has its own event, its own decision, and a hook that continues naturally from chapter 20.', FALSE, 40, 364, DATEADD('DAY', 1, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
