INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('69e29391-01b8-5d4c-9f67-806819ceb302', 'c915e4bd-a513-59da-85df-24258cb1895d', 21, 'Chapter 21: Extended Arc 1', 'parallel-desk-chapter-21', 'Novel: Parallel Desk. Chapter 21 - Extended Arc 1. This paid extra chapter continues after the first twenty chapters and keeps the same parallel lives, regret, and self-discovery direction. Premise reminder: An office worker receives messages from herself in a parallel timeline where she made every different choice. The scene follows Nora Yuen through a modern city office tower, a shared apartment, and the coffee shop where both versions of Nora meet every Thursday, with the main conflict still pressing forward: the two Noras must cooperate to prevent an event that will collapse both timelines, but their goals are opposite. Nora compares both timelines one decision at a time, learning which regrets are warnings and which are traps set by the collapse between worlds. The chapter advances the extended arc by focusing on step 1 of 20: a new clue appears, but accepting it forces the protagonist to trust someone whose motives remain unclear. By the ending, chapter 21 has its own event, its own decision, and a hook that continues naturally from chapter 20.', FALSE, 40, 469, DATEADD('DAY', 1, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
