INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('f99993ae-7042-552c-afa7-65342f7746fc', '519dc999-cf18-57de-8858-45cf18b794e2', 21, 'Chapter 21: Extended Arc 1', 'second-skin-chapter-21', 'Novel: Second Skin. Chapter 21 - Extended Arc 1. This paid extra chapter continues after the first twenty chapters and keeps the same undercover romance and moral loyalty direction. Premise reminder: An undercover agent falls in love with the target of her investigation and must decide which identity is the real one. The scene follows Agent Calla Neve through a harbor city of imported fashions, underground auction houses, and rooftop cafes with long sight lines, with the main conflict still pressing forward: Calla''s cover identity has grown closer to the target than her real self, and the mission deadline is now two days away. Calla''s cover identity keeps pulling her toward the target, while the mission files prove that love and loyalty are both being used against her. The chapter advances the extended arc by focusing on step 1 of 7: a new clue appears, but accepting it forces the protagonist to trust someone whose motives remain unclear. By the ending, chapter 21 has its own event, its own decision, and a hook that continues naturally from chapter 20.', FALSE, 40, 514, DATEADD('DAY', 1, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
