INSERT INTO chapters (id, novel_id, chapter_number, title, slug, content, is_free, coin_price, view_count, created_at, updated_at) VALUES ('8a69db96-61e9-5fbe-bc6a-ced6593f2b3a', '8d2c6065-4d66-5d7f-8349-b8381f337f23', 21, 'Chapter 21: Extended Arc 1', 'fog-parliament-chapter-21', 'Novel: Fog Parliament. Chapter 21 - Extended Arc 1. This paid extra chapter continues after the first twenty chapters and keeps the same political manipulation and supernatural fog direction. Premise reminder: A junior delegate arrives at a fog-shrouded parliament where votes disappear overnight and the majority is always whoever woke up last. The scene follows Delegate Oswin Frey through a parliament building perpetually wrapped in coastal fog, with ink-stained corridors and offices that rearrange nightly, with the main conflict still pressing forward: Oswin must pass a land-rights bill before the fog erases the vote record again, and someone is feeding the fog deliberately. Oswin studies the parliament''s moving rooms and vanishing vote records, tracing the fog to a faction that wins only when memory fails. The chapter advances the extended arc by focusing on step 1 of 9: a new clue appears, but accepting it forces the protagonist to trust someone whose motives remain unclear. By the ending, chapter 21 has its own event, its own decision, and a hook that continues naturally from chapter 20.', FALSE, 40, 529, DATEADD('DAY', 1, CURRENT_TIMESTAMP), CURRENT_TIMESTAMP);
